
.prison-status {
  width: 100%;
  max-width: 720px;
  background-color: var(--c-bg);
  border: 2px solid var(--c-border);
  display: flex;
  flex-direction: column;
  font-family: var(--font-prison);
  color: var(--c-text);
  font-size: 13px;
  line-height: 1.4;
  margin: 0 auto;
  box-shadow:
    0 0 0 1px var(--c-border-strong) inset,
    0 4px 20px rgba(0, 0, 0, 0.6);
  position: relative;
  overflow: hidden;
}

/* 铁栏装饰条 */
.bars-decor {
  height: 6px;
  background: repeating-linear-gradient(
    90deg,
    var(--c-border) 0px,
    var(--c-border) 3px,
    var(--c-bg) 3px,
    var(--c-bg) 8px
  );
  flex-shrink: 0;
}

.bars-bottom {
  border-top: 1px solid var(--c-border);
}

.panels-container {
  display: flex;
  flex-direction: column;
  gap: 0;
}
