
.header-bar {
  display: flex;
  flex-direction: column;
  background: linear-gradient(180deg, var(--c-surface-raised) 0%, var(--c-surface) 100%);
  border-bottom: 2px solid var(--c-border);
  flex-shrink: 0;
}

.header-row {
  display: flex;
}

.header-row + .header-row {
  border-top: 1px solid var(--c-border);
}

.header-row-time-week {
  flex: 1;
}

.header-cell {
  display: flex;
  align-items: center;
  gap: 5px;
  padding: 7px 10px;
  border-right: 1px solid var(--c-border);
  font-size: 0.82rem;
  overflow: hidden;
  white-space: nowrap;
  flex: 1;
  min-width: 0;
}

.header-cell:last-child {
  border-right: none;
}

.header-date {
  justify-content: center;
}

.header-time,
.header-weekday {
  justify-content: center;
}

.header-location {
  justify-content: center;
}

.cell-icon {
  color: var(--c-accent);
  font-size: 0.9rem;
  flex-shrink: 0;
}

.cell-label {
  color: var(--c-text-dim);
  font-size: 0.72rem;
  text-transform: uppercase;
  letter-spacing: 1px;
  flex-shrink: 0;
}

.cell-value {
  color: var(--c-text);
  font-weight: bold;
  overflow: hidden;
  text-overflow: ellipsis;
  min-width: 0;
}
