
.char-panel {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.field-block {
  background: var(--c-bg);
  border: 1px solid var(--c-border);
  border-left: 3px solid var(--c-accent);
  padding: 7px 9px;
}

.field-thought {
  border-left-color: #6b4a7a;
}

.field-desire {
  border-left-color: var(--c-danger);
}

.field-attire {
  border-left-color: #4a6a8a;
}

.field-label {
  display: flex;
  align-items: center;
  gap: 5px;
  font-size: 0.75rem;
  color: var(--c-text-muted);
  text-transform: uppercase;
  letter-spacing: 1px;
  margin-bottom: 4px;
}

.label-icon {
  font-size: 0.82rem;
}

.value-badge {
  margin-left: auto;
  font-size: 0.9rem;
  font-weight: bold;
  text-transform: none;
  letter-spacing: 0;
}

.field-content {
  font-size: 0.82rem;
  color: var(--c-text);
  line-height: 1.45;
}

.field-thought-content {
  font-style: italic;
  color: #c4b8d4;
}

/* 欲望值进度条 */
.desire-bar {
  position: relative;
  height: 12px;
  background: var(--c-bg);
  border: 1px solid var(--c-border);
  overflow: hidden;
  margin-bottom: 3px;
}

.desire-fill {
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  transition: width 0.3s ease, background 0.3s ease;
  box-shadow: 0 0 6px rgba(200, 134, 42, 0.3);
}

.desire-marker {
  position: absolute;
  top: 0;
  bottom: 0;
  width: 1px;
  background: var(--c-border);
  opacity: 0.5;
}

.desire-marker-25 { left: 25%; }
.desire-marker-50 { left: 50%; }
.desire-marker-75 { left: 75%; }

.desire-status {
  font-size: 0.72rem;
  text-align: right;
  font-weight: bold;
}

/* 身体状态网格 */
.body-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 6px;
}

.body-cell {
  background: var(--c-bg);
  border: 1px solid var(--c-border);
  padding: 6px 8px;
}

.body-cell-wide {
  grid-column: 1 / -1;
}

.body-cell-label {
  font-size: 0.72rem;
  color: var(--c-text-muted);
  text-transform: uppercase;
  letter-spacing: 1px;
  margin-bottom: 3px;
  display: flex;
  align-items: center;
  gap: 4px;
}

.body-cell-label::before {
  content: '';
}

.body-icon {
  font-size: 0.82rem;
  line-height: 1;
}

.body-cell-content {
  font-size: 0.78rem;
  color: var(--c-text);
  line-height: 1.4;
}

.pregnancy-tag {
  display: inline-block;
  padding: 1px 6px;
  border: 1px solid var(--c-border);
  font-size: 0.75rem;
  color: var(--c-text-muted);
}

.pregnancy-tag.pregnancy-yes {
  color: var(--c-danger);
  border-color: var(--c-danger);
  background: rgba(184, 52, 58, 0.1);
  font-weight: bold;
}

/* 子宫精液量动态条 */
.semen-value {
  margin-left: auto;
  font-size: 0.78rem;
  font-weight: bold;
  color: #e8e0d0;
  text-transform: none;
  letter-spacing: 0;
}

.semen-bar {
  position: relative;
  height: 14px;
  background: var(--c-bg);
  border: 1px solid var(--c-border);
  overflow: hidden;
  margin-top: 2px;
}

.semen-fill {
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  background: linear-gradient(180deg, #f5f0e8 0%, #e8dfd0 50%, #ddd4c4 100%);
  transition: width 0.3s ease;
  box-shadow: 0 0 4px rgba(245, 240, 232, 0.3);
}

.semen-tick {
  position: absolute;
  top: 0;
  bottom: 0;
  width: 1px;
  background: var(--c-border);
  opacity: 0.4;
}

.semen-tick-25 { left: 25%; }
.semen-tick-50 { left: 50%; }
.semen-tick-75 { left: 75%; }

.semen-tick-label {
  position: absolute;
  bottom: -1px;
  font-size: 0.55rem;
  color: var(--c-text-dim);
  line-height: 1;
  transform: translateX(-50%);
}

.semen-tick-label-0 { left: 2%; transform: translateX(0); }
.semen-tick-label-25 { left: 25%; }
.semen-tick-label-50 { left: 50%; }
.semen-tick-label-75 { left: 75%; }
.semen-tick-label-100 { left: 98%; transform: translateX(-100%); }

@media (max-width: 600px) {
  .body-grid {
    grid-template-columns: 1fr;
  }
}
