
.prison-panel {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

/* 指标行 */
.metric-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 8px;
}

.metric-block {
  background: var(--c-bg);
  border: 1px solid var(--c-border);
  padding: 7px 9px;
}

.metric-header {
  display: flex;
  align-items: center;
  gap: 5px;
  margin-bottom: 5px;
}

.metric-icon {
  font-size: 0.82rem;
}

.metric-name {
  font-size: 0.75rem;
  color: var(--c-text-muted);
  letter-spacing: 0.5px;
}

.metric-value {
  margin-left: auto;
  font-size: 0.9rem;
  font-weight: bold;
}

.metric-bar {
  height: 10px;
  background: var(--c-bg);
  border: 1px solid var(--c-border);
  overflow: hidden;
  margin-bottom: 3px;
}

.metric-fill {
  height: 100%;
  transition: width 0.3s ease, background 0.3s ease;
}

.metric-status {
  font-size: 0.72rem;
  font-weight: bold;
  text-align: right;
}

/* 帮派忠诚度 */
.faction-section {
  background: var(--c-bg);
  border: 1px solid var(--c-border);
  padding: 8px 9px;
}

.faction-title {
  display: flex;
  align-items: center;
  gap: 5px;
  font-size: 0.78rem;
  color: var(--c-text-muted);
  text-transform: uppercase;
  letter-spacing: 1px;
  margin-bottom: 6px;
  padding-bottom: 4px;
  border-bottom: 1px solid var(--c-border);
}

.faction-title-icon {
  color: var(--c-danger);
}

.faction-list {
  display: flex;
  flex-direction: column;
  gap: 5px;
}

.faction-row {
  display: flex;
  align-items: center;
  gap: 8px;
}

.faction-info {
  display: flex;
  align-items: center;
  gap: 5px;
  flex-shrink: 0;
  width: 140px;
}

.faction-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  flex-shrink: 0;
  box-shadow: 0 0 4px currentColor;
}

.faction-name {
  font-size: 0.78rem;
  font-weight: bold;
  color: var(--c-text);
  white-space: nowrap;
}

.faction-territory {
  font-size: 0.65rem;
  color: var(--c-text-dim);
}

.faction-bar-wrapper {
  display: flex;
  align-items: center;
  gap: 6px;
  flex: 1;
  min-width: 0;
}

.faction-bar {
  flex: 1;
  height: 8px;
  background: var(--c-surface-raised);
  border: 1px solid var(--c-border);
  overflow: hidden;
  min-width: 0;
}

.faction-bar-fill {
  height: 100%;
  transition: width 0.3s ease;
  box-shadow: 0 0 4px currentColor;
}

.faction-value {
  font-size: 0.75rem;
  font-weight: bold;
  min-width: 32px;
  text-align: right;
}

/* 黑石卡 */
.card-block {
  background: var(--c-bg);
  border: 1px solid var(--c-border);
  border-left: 3px solid var(--c-accent);
  padding: 7px 9px;
}

.card-label {
  display: flex;
  align-items: center;
  gap: 5px;
  font-size: 0.75rem;
  color: var(--c-text-muted);
  text-transform: uppercase;
  letter-spacing: 1px;
  margin-bottom: 4px;
}

.card-icon {
  font-size: 0.85rem;
}

.card-holder {
  font-size: 0.88rem;
  padding: 4px 8px;
  background: var(--c-surface-raised);
  border: 1px solid var(--c-border);
}

.holder-name {
  color: var(--c-accent);
  font-weight: bold;
}

.holder-empty {
  color: var(--c-text-dim);
  font-style: italic;
}

.card-empty {
  border-style: dashed;
}

.card-hint {
  font-size: 0.68rem;
  color: var(--c-text-dim);
  margin-top: 3px;
}

@media (max-width: 600px) {
  .metric-row {
    grid-template-columns: 1fr;
  }

  .faction-info {
    width: 110px;
  }

  .faction-territory {
    display: none;
  }
}
